const amqp = require('amqplib');
const { Pool } = require('pg');

// RabbitMQ connection details
const rabbitmqUrl = 'amqp://localhost';
const queueName = 'events';

// PostgreSQL database connection details
const dbConfig = {
  user: 'your_user',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
};

const pool = new Pool(dbConfig);

async function connectToRabbitMQ() {
  try {
    const connection = await amqp.connect(rabbitmqUrl);
    const channel = await connection.createChannel();
    await channel.assertQueue(queueName, { durable: false });
    console.log(`Waiting for messages in ${queueName}. To exit press CTRL+C`);

    channel.consume(queueName, async (msg) => {
      if (msg !== null) {
        try {
          const message = JSON.parse(msg.content.toString());
          await handleMessage(message);
          channel.ack(msg);
        } catch (error) {
          console.error('Error processing message:', error);
          channel.nack(msg, false, true); // Reject and requeue the message
        }
      }
    });
  } catch (error) {
    console.error('Failed to connect to RabbitMQ:', error);
  }
}

async function handleMessage(message) {
  try {
    switch (message.type) {
      case 'INSERT':
        await insertData(message.payload);
        break;
      case 'UPDATE':
        await updateData(message.payload);
        break;
      case 'DELETE':
        await deleteData(message.payload);
        break;
      default:
        console.warn(`Unknown message type: ${message.type}`);
    }
  } catch (error) {
    console.error('Error handling message:', error);
  }
}

async function insertData(data) {
  const query = 'INSERT INTO your_table (column1, column2) VALUES ($1, $2)';
  await pool.query(query, [data.column1, data.column2]);
}

async function updateData(data) {
  const query = 'UPDATE your_table SET column1 = $1 WHERE id = $2';
  await pool.query(query, [data.column1, data.id]);
}

async function deleteData(data) {
  const query = 'DELETE FROM your_table WHERE id = $1';
  await pool.query(query, [data.id]);
}

connectToRabbitMQ();